using ChurnPredictor;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn-model.zip");

// Train the model at startup and log evaluation metrics
var report = ChurnModelTrainer.Train(dataPath, modelPath);
Console.WriteLine(report);

// Use pooled PredictionEngine (thread-safe for web apps)
builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapPost("/predict", (CustomerInput input,
    PredictionEnginePool<CustomerData, ChurnPrediction> pool) =>
{
    var customerData = new CustomerData
    {
        Age = input.Age,
        Income = input.Income,
        Region = input.Region,
        PurchaseHistory = input.PurchaseHistory,
    };

    var prediction = pool.Predict(customerData);

    return Results.Ok(new
    {
        WillChurn = prediction.Churned,
        prediction.Probability,
    });
});

app.Run();

public record CustomerInput(float Age, float Income, string Region, float PurchaseHistory);

